def get_package_hash(package_name: str, version: str) -> str:
    """Get expected hash for a package from PyPI JSON API"""
    import urllib.request
    import urllib.error
    
    try:
        url = f"https://pypi.org/pypi/{package_name}/{version}/json"
        with urllib.request.urlopen(url, timeout=10) as response:
            data = json.loads(response.read().decode())
            urls = data.get('urls', [])
            for url_info in urls:
                if url_info.get('packagetype') == 'bdist_wheel' or url_info.get('packagetype') == 'sdist':
                    return url_info.get('digests', {}).get('sha256', '')
    except (urllib.error.URLError, json.JSONDecodeError, KeyError):
        pass
    return ''

def verify_requirements_file(requirements_file: str) -> bool:
    """Verify requirements file exists and is readable"""
    path = Path(requirements_file)
    if not path.exists():
        print(f"Error: Requirements file {requirements_file} not found", file=sys.stderr)
        return False
    if not path.is_file():
        print(f"Error: {requirements_file} is not a file", file=sys.stderr)
        return False
    return True

def create_hash_verified_requirements(requirements_file: str) -> str:
    """Create a requirements file with hash verification"""
    temp_dir = tempfile.mkdtemp()
    temp_req_file = os.path.join(temp_dir, 'requirements_verified.txt')
    
    with open(requirements_file, 'r') as f:
        lines = f.readlines()
    
    verified_lines = []
    for line in lines:
        line = line.strip()
        if not line or line.startswith('#'):
            verified_lines.append(line)
            continue
        
        if '--hash=' in line:
            verified_lines.append(line)
        else:
            parts = line.split('==')
            if len(parts) == 2:
                package_name = parts[0].strip()
                version = parts[1].strip()
                pkg_hash = get_package_hash(package_name, version)
                if pkg_hash:
                    verified_lines.append(f"{package_name}=={version} --hash=sha256:{pkg_hash}")
                else:
                    verified_lines.append(line)
            else:
                verified_lines.append(line)
    
    with open(temp_req_file, 'w') as f:
        f.write('\n'.join(verified_lines))
    
    return temp_req_file

def install_with_pip_audit() -> bool:
    """Install pip-audit for vulnerability scanning"""
    try:
        subprocess.run(
            [sys.executable, '-m', 'pip', 'install', '--quiet', 'pip-audit'],
            check=True,
            capture_output=True
        )
        return True
    except subprocess.CalledProcessError:
        return False

def scan_vulnerabilities() -> bool:
    """Scan installed packages for known vulnerabilities"""
    try:
        result = subprocess.run(
            [sys.executable, '-m', 'pip_audit', '--desc'],
            capture_output=True,
            text=True
        )
        if result.returncode != 0:
            print("WARNING: Vulnerabilities detected:", file=sys.stderr)
            print(result.stdout, file=sys.stderr)
            return False
        return True
    except (subprocess.CalledProcessError, FileNotFoundError):
        print("WARNING: Could not run vulnerability scan", file=sys.stderr)
        return True

def freeze_installed_packages(output_file: str = 'installed_packages.txt'):
    """Freeze installed packages with hashes for audit trail"""
    try:
        result = subprocess.run(
            [sys.executable, '-m', 'pip', 'freeze'],
            capture_output=True,
            text=True,
            check=True
        )
        with open(output_file, 'w') as f:
            f.write(result.stdout)
        print(f"Installed packages frozen to {output_file}")
    except subprocess.CalledProcessError as e:
        print(f"Warning: Could not freeze packages: {e}", file=sys.stderr)

