def install_requirements(requirements_file: str = 'requirements.txt', upgrade: bool = False):
    """Install requirements with security measures"""
    
    if not verify_requirements_file(requirements_file):
        sys.exit(1)
    
    print("Starting secure package installation...")
    
    print("Upgrading pip, setuptools, and wheel...")
    try:
        subprocess.run(
            [sys.executable, '-m', 'pip', 'install', '--upgrade', 'pip', 'setuptools', 'wheel'],
            check=True,
            capture_output=True
        )
    except subprocess.CalledProcessError as e:
        print(f"Error upgrading pip: {e}", file=sys.stderr)
        sys.exit(1)
    
    install_cmd = [
        sys.executable, '-m', 'pip', 'install',
        '-r', requirements_file,
        '--no-cache-dir',
        '--require-hashes' if os.getenv('REQUIRE_HASHES', 'false').lower() == 'true' else '--no-deps',
        '--only-binary', ':all:' if os.getenv('ONLY_BINARY', 'false').lower() == 'true' else '',
    ]
    
    install_cmd = [arg for arg in install_cmd if arg]
    
    if upgrade:
        install_cmd.append('--upgrade')
    
    if os.getenv('PIP_INDEX_URL'):
        install_cmd.extend(['--index-url', os.getenv('PIP_INDEX_URL')])
    
    if os.getenv('PIP_TRUSTED_HOST'):
        install_cmd.extend(['--trusted-host', os.getenv('PIP_TRUSTED_HOST')])
    
    print(f"Installing packages from {requirements_file}...")
    try:
        subprocess.run(install_cmd, check=True)
    except subprocess.CalledProcessError as e:
        print(f"Error installing packages: {e}", file=sys.stderr)
        sys.exit(1)
    
    if '--no-deps' in install_cmd:
        print("Installing dependencies...")
        deps_cmd = [
            sys.executable, '-m', 'pip', 'install',
            '-r', requirements_file,
            '--no-cache-dir'
        ]
        if upgrade:
            deps_cmd.append('--upgrade')
        try:
            subprocess.run(deps_cmd, check=True)
        except subprocess.CalledProcessError as e:
            print(f"Error installing dependencies: {e}", file=sys.stderr)
            sys.exit(1)
    
    verify_package_signatures()
    
    if os.getenv('ENABLE_VULNERABILITY_SCAN', 'true').lower() == 'true':
        print("Installing vulnerability scanner...")
        if install_with_pip_audit():
            print("Scanning for vulnerabilities...")
            if not scan_vulnerabilities():
                if os.getenv('FAIL_ON_VULNERABILITIES', 'false').lower() == 'true':
                    print("CRITICAL: Vulnerabilities found, failing build", file=sys.stderr)
                    sys.exit(1)
    
    freeze_installed_packages()
    
    print("Package installation completed successfully")

